import{_ as t,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"OpenAI 额度: 查询限制 | opencode-mystatus","description":"学习查询 OpenAI 的 3 小时和 24 小时额度使用情况。掌握主次窗口、进度条、重置时间和订阅类型信息。","frontmatter":{"title":"OpenAI 额度: 查询限制 | opencode-mystatus","subtitle":"OpenAI 额度: 查询限制","sidebarTitle":"OpenAI 额度","description":"学习查询 OpenAI 的 3 小时和 24 小时额度使用情况。掌握主次窗口、进度条、重置时间和订阅类型信息。","tags":["OpenAI","Quota Query","API Quota"],"prerequisite":["/vbgate/opencode-mystatus/start/quick-start","/vbgate/opencode-mystatus/start/understanding-output"],"order":999},"headers":[],"relativePath":"vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),i={name:"vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function s(r,e,l,d,p,u){return o(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="openai-quota-query-3-hour-24-hour-limits" tabindex="-1">OpenAI Quota Query: 3-Hour &amp; 24-Hour Limits <a class="header-anchor" href="#openai-quota-query-3-hour-24-hour-limits" aria-label="Permalink to &quot;OpenAI Quota Query: 3-Hour &amp; 24-Hour Limits&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Use <code>/mystatus</code> to query OpenAI Plus/Team/Pro subscription quotas</li><li>Understand 3-hour and 24-hour quota limit information in the output</li><li>Distinguish between primary and secondary windows</li><li>Handle token expiration properly</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>OpenAI API calls have rate limits, and exceeding them triggers temporary access restrictions. But you don&#39;t know:</p><ul><li>How much quota remains?</li><li>Which window is active—the 3-hour or 24-hour one?</li><li>When will it reset?</li><li>Why do you sometimes see data for two windows?</li></ul><p>Without timely access to this information, your progress on coding with ChatGPT or working on projects may be impacted.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>When you:</p><ul><li>Need to frequently use the OpenAI API for development</li><li>Notice slower responses or rate limiting</li><li>Want to understand team account usage</li><li>Need to know when quotas will refresh</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>OpenAI applies two types of rate limiting windows for API calls:</p><table tabindex="0"><thead><tr><th>Window Type</th><th>Duration</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Primary Window</strong></td><td>Returned by OpenAI server</td><td>Prevents excessive calls within a short time</td></tr><tr><td><strong>Secondary Window</strong></td><td>Returned by OpenAI server (may not exist)</td><td>Prevents long-term overuse</td></tr></tbody></table><p>mystatus queries both windows in parallel and displays:</p><ul><li>Percentage used</li><li>Remaining quota progress bar</li><li>Time until reset</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Window duration is returned by the OpenAI server and may vary by subscription type (Plus, Team, Pro).</p></div><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-execute-the-query-command" tabindex="-1">Step 1: Execute the Query Command <a class="header-anchor" href="#step-1-execute-the-query-command" aria-label="Permalink to &quot;Step 1: Execute the Query Command&quot;">​</a></h3><p>In OpenCode, type <code>/mystatus</code>. The system automatically queries quotas for all configured platforms.</p><p><strong>You should see</strong>: Quota information for OpenAI, Zhipu AI, Z.ai, Copilot, Google Cloud, and other platforms (depending on which platforms you&#39;ve configured).</p><h3 id="step-2-locate-the-openai-section" tabindex="-1">Step 2: Locate the OpenAI Section <a class="header-anchor" href="#step-2-locate-the-openai-section" aria-label="Permalink to &quot;Step 2: Locate the OpenAI Section&quot;">​</a></h3><p>Find the <code>## OpenAI Account Quota</code> section in the output.</p><p><strong>You should see</strong>: Something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="step-3-interpret-the-primary-window" tabindex="-1">Step 3: Interpret the Primary Window <a class="header-anchor" href="#step-3-interpret-the-primary-window" aria-label="Permalink to &quot;Step 3: Interpret the Primary Window&quot;">​</a></h3><p>The <strong>Primary Window</strong> (primary_window) typically shows:</p><ul><li><strong>Window name</strong>: Such as <code>3-hour limit</code> or <code>24-hour limit</code></li><li><strong>Progress bar</strong>: Visual representation of remaining quota ratio</li><li><strong>Remaining percentage</strong>: Such as <code>60% remaining</code></li><li><strong>Reset time</strong>: Such as <code>Resets in: 2h 30m</code></li></ul><p><strong>You should see</strong>:</p><ul><li>Window name displays the duration (3-hour / 24-hour)</li><li>A fuller progress bar means more quota remaining; an emptier bar means closer to depletion</li><li>Reset time is a countdown—quota refreshes when it reaches zero</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>If you see <code>Limit reached!</code>, the current window quota is exhausted and you need to wait for reset.</p></div><h3 id="step-4-check-the-secondary-window-if-present" tabindex="-1">Step 4: Check the Secondary Window (if present) <a class="header-anchor" href="#step-4-check-the-secondary-window-if-present" aria-label="Permalink to &quot;Step 4: Check the Secondary Window (if present)&quot;">​</a></h3><p>If OpenAI returns secondary window data, you&#39;ll see:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>Secondary window shows quota for another time dimension (usually 24 hours)</li><li>May have a different remaining percentage than the primary window</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The secondary window is an independent quota pool. Exhausting the primary window doesn&#39;t affect the secondary window, and vice versa.</p></div><h3 id="step-5-view-subscription-type" tabindex="-1">Step 5: View Subscription Type <a class="header-anchor" href="#step-5-view-subscription-type" aria-label="Permalink to &quot;Step 5: View Subscription Type&quot;">​</a></h3><p>You can see the subscription type in the <code>Account</code> line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Subscription type</span></span></code></pre></div><p><strong>Common subscription types</strong>:</p><ul><li><code>plus</code>: Personal Plus subscription</li><li><code>team</code>: Team/organization subscription</li><li><code>pro</code>: Pro subscription</li></ul><p><strong>You should see</strong>:</p><ul><li>Your account type displayed in parentheses after the email</li><li>Different subscription types may have different limits</li></ul><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Verify your understanding:</p><table tabindex="0"><thead><tr><th>Scenario</th><th>You should see</th></tr></thead><tbody><tr><td>60% remaining in primary window</td><td>Progress bar about 60% full, displaying <code>60% remaining</code></td></tr><tr><td>Resets in 2.5 hours</td><td>Shows <code>Resets in: 2h 30m</code></td></tr><tr><td>Limit reached</td><td>Displays <code>Limit reached!</code></td></tr><tr><td>Secondary window present</td><td>Both primary and secondary windows show their own data lines</td></tr></tbody></table><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="❌-mistake-not-refreshing-after-token-expiration" tabindex="-1">❌ Mistake: Not Refreshing After Token Expiration <a class="header-anchor" href="#❌-mistake-not-refreshing-after-token-expiration" aria-label="Permalink to &quot;❌ Mistake: Not Refreshing After Token Expiration&quot;">​</a></h3><p><strong>Error symptom</strong>: You see the message <code>⚠️ OAuth token expired</code> (English) or <code>⚠️ OAuth 授权已过期</code> (Chinese)</p><p><strong>Cause</strong>: The OAuth Token has expired (specific duration controlled by the server), preventing quota queries.</p><p><strong>Correct approach</strong>:</p><ol><li>Re-login to OpenAI in OpenCode</li><li>Token refreshes automatically</li><li>Run <code>/mystatus</code> query again</li></ol><h3 id="❌-mistake-confusing-primary-and-secondary-windows" tabindex="-1">❌ Mistake: Confusing Primary and Secondary Windows <a class="header-anchor" href="#❌-mistake-confusing-primary-and-secondary-windows" aria-label="Permalink to &quot;❌ Mistake: Confusing Primary and Secondary Windows&quot;">​</a></h3><p><strong>Error symptom</strong>: Thinking there&#39;s only one window quota, then the primary window is exhausted while the secondary window is still available</p><p><strong>Cause</strong>: The two windows are independent quota pools.</p><p><strong>Correct approach</strong>:</p><ul><li>Pay attention to reset times for both windows</li><li>Primary window resets faster; secondary window resets slower</li><li>Distribute usage reasonably to avoid long-term overage in any window</li></ul><h3 id="❌-mistake-ignoring-team-account-id" tabindex="-1">❌ Mistake: Ignoring Team Account ID <a class="header-anchor" href="#❌-mistake-ignoring-team-account-id" aria-label="Permalink to &quot;❌ Mistake: Ignoring Team Account ID&quot;">​</a></h3><p><strong>Error symptom</strong>: Team subscription displays usage that isn&#39;t yours</p><p><strong>Cause</strong>: Team subscriptions require passing a team account ID; otherwise, the query might be for the default account.</p><p><strong>Correct approach</strong>:</p><ul><li>Ensure you&#39;re logged into the correct team account in OpenCode</li><li>Token automatically includes <code>chatgpt_account_id</code></li></ul><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>mystatus queries quotas by calling the official OpenAI API:</p><ul><li>Supports OAuth authentication (Plus/Team/Pro)</li><li>Displays primary and secondary windows (if present)</li><li>Progress bars visualize remaining quota</li><li>Countdown shows reset time</li><li>Automatically detects token expiration</li></ul><h2 id="coming-up-next" tabindex="-1">Coming Up Next <a class="header-anchor" href="#coming-up-next" aria-label="Permalink to &quot;Coming Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn about <strong><a href="./../zhipu-usage/">Zhipu AI and Z.ai Quota Query</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>What the 5-hour Token limit means</li><li>How to check MCP monthly quotas</li><li>Warning prompts when usage exceeds 80%</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>OpenAI quota query entry</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>OpenAI API call</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>Format output</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>JWT Token parsing</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>Extract user email</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Token expiration check</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>OpenAIAuthData type definition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Constants</strong>:</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>: Official OpenAI quota query API</li></ul><p><strong>Key functions</strong>:</p><ul><li><code>queryOpenAIUsage(authData)</code>: Main function for querying OpenAI quota</li><li><code>fetchOpenAIUsage(accessToken)</code>: Call the OpenAI API</li><li><code>formatOpenAIUsage(data, email)</code>: Format output</li><li><code>parseJwt(token)</code>: Parse JWT Token (non-standard library implementation)</li><li><code>getEmailFromJwt(token)</code>: Extract user email from Token</li><li><code>getAccountIdFromJwt(token)</code>: Extract team account ID from Token</li></ul></details>`,70)])])}const m=t(i,[["render",s]]);export{h as __pageData,m as default};
